setupGuide.code:
# coverage.yml
route: { claims: claims_team, unclear: licensed_agent }
always_surface: [deductible, exclusions, limits]

examples.output:
{
  "question": "Is windshield damage covered?",
  "covered_by_policy_doc": true,
  "explanation": "Your policy's comprehensive coverage includes glass damage such as a windshield, subject to your deductible. So windshield damage would generally fall under comprehensive coverage per your policy.",
  "citation": "Auto Policy, Comprehensive Coverage §C-3 'Glass'",
  "limits_exclusions": ["$100 comprehensive deductible applies", "Coverage is subject to the comprehensive section conditions"],
  "claim_guarantee": "none — coverage explanation is not a claim decision",
  "route_to": "self_serve",
  "escalation": { "needed": false, "reason": "" }
}

{
  "question": "Coverage when using a personal car for food delivery",
  "covered_by_policy_doc": false,
  "explanation": "Your policy document doesn't clearly address using your personal vehicle for paid delivery or rideshare work, which is often handled differently (sometimes excluded or requiring a separate endorsement). I don't want to give you a wrong answer on something this important.",
  "citation": "",
  "limits_exclusions": ["Commercial/delivery use is commonly excluded or requires an endorsement — but your document is not explicit, so this needs confirmation"],
  "claim_guarantee": "none — coverage explanation is not a claim decision",
  "route_to": "licensed_agent",
  "escalation": { "needed": true, "reason": "Coverage for delivery use is not clearly addressed in the policy — routed to a licensed agent rather than guessed." }
}

{
  "question": "Will my claim for an at-fault collision definitely be paid?",
  "covered_by_policy_doc": true,
  "explanation": "Your policy includes liability coverage and, if you carry it, collision coverage that can apply to at-fault accidents, subject to your limits and deductible (per the policy). But I can't tell you a specific claim 'will definitely be paid' — that decision depends on the facts of the incident, the investigation, and your adjuster. What I can do is explain what your policy covers and get your claim to the right people.",
  "citation": "Auto Policy, Liability §A-1; Collision §C-1 (if elected)",
  "limits_exclusions": ["Collision deductible applies", "Coverage subject to policy limits and conditions; specific facts may affect the claim"],
  "claim_guarantee": "none — coverage explanation is not a claim decision",
  "route_to": "claims",
  "escalation": { "needed": true, "reason": "Member wants a claim-payment guarantee — explained coverage, declined to promise an outcome, and routed to claims." }
}
